"use client";

import { useState } from "react";

export default function FAQ() {
  const [openIndex, setOpenIndex] = useState<number | null>(0);

  const faqs = [
    {
      question: "How does the audit work?",
      answer:
        "Our algorithm analyzes your AI tool usage patterns, current plans, and team size to identify redundancies and optimization opportunities. We then generate personalized recommendations based on your specific use case.",
    },
    {
      question: "Is my data secure?",
      answer:
        "Yes. We use industry-standard encryption and never store your personal data longer than necessary. Your audit results are private and can only be accessed via a secure link that you control.",
    },
    {
      question: "Can I save and share my audit report?",
      answer:
        "Absolutely. After generating your audit, you'll receive a unique public URL that you can share with your team or stakeholders. Reports are saved for 30 days.",
    },
    {
      question: "What if I use tools not listed?",
      answer:
        "We're constantly adding support for new AI tools. If your tool isn't listed, select 'Other' and provide details in the form. We'll include it in our analysis and add it to our platform.",
    },
    {
      question: "Do you offer team or enterprise plans?",
      answer:
        "Currently, we focus on startups and small teams. For enterprise inquiries, please contact our sales team at sales@aispendauditor.com.",
    },
  ];

  return (
    <section className="bg-white py-20 sm:py-32">
      <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Section Header */}
        <div className="text-center mb-16">
          <h2 className="text-4xl sm:text-5xl font-bold text-slate-900 mb-4">
            Frequently Asked Questions
          </h2>
          <p className="text-lg text-slate-600">
            Everything you need to know about AI Spend Auditor.
          </p>
        </div>

        {/* FAQ Items */}
        <div className="space-y-4">
          {faqs.map((faq, index) => (
            <div
              key={index}
              className="border border-slate-200 rounded-lg overflow-hidden hover:border-slate-300 transition-colors"
            >
              <button
                onClick={() => setOpenIndex(openIndex === index ? null : index)}
                className="w-full px-6 py-4 flex items-center justify-between bg-white hover:bg-slate-50 transition-colors"
              >
                <h3 className="text-left font-semibold text-slate-900">
                  {faq.question}
                </h3>
                <span
                  className={`text-slate-600 transition-transform flex-shrink-0 ml-4 ${
                    openIndex === index ? "rotate-180" : ""
                  }`}
                >
                  ▼
                </span>
              </button>

              {openIndex === index && (
                <div className="px-6 py-4 bg-slate-50 border-t border-slate-200">
                  <p className="text-slate-700 leading-relaxed">{faq.answer}</p>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* CTA */}
        <div className="mt-16 text-center">
          <p className="text-slate-600 mb-4">Still have questions?</p>
          <a
            href="mailto:hello@aispendauditor.com"
            className="inline-block px-6 py-3 bg-slate-100 hover:bg-slate-200 text-slate-900 font-semibold rounded-lg transition-colors"
          >
            Contact Us
          </a>
        </div>
      </div>
    </section>
  );
}
